var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>파견된 직원들이 전원 연락 두절 상태입니다!</color>","JPN":"<color=#ffd34c>派遣された社員全員から連絡が途絶えています！</color>","ENG":"<color=#ffd34c>We lost comms to all the operatives!</color>","TWN":"<color=#ffd34c>派出去的員工目前都失聯中！</color>"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>신호가 끊긴 그릴 파티 녀석들을 발견했다! 전부 기절해 있어!</color>","JPN":"<color=#ffd34c>信号が途切れたグリルパーティーのやつらを発見したぞ！　全員気絶している！</color>","ENG":"<color=#ffd34c>I've got eyes on Grill Party that went radio silent! They're all unconscious!</color>","TWN":"<color=#ffd34c>發現信號中斷的格里爾派提的傢伙們！全數昏厥中。</color>"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L5_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"시, 시청자 여러분! 저희는 지금 샤레이드에 나와 있는데요……!","JPN":"し、視聴者の皆さん！　私たちは今シャレードに来ています……！","ENG":"H-hello everyone… We're in Charade right now!","TWN":"觀…觀眾朋友！我們現在的位置是查雷德……！"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L6_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"저기 하늘에 함선들 보이세요? 샤레이드에 있는 태스크포스들은 전부 출동한 거 같아요!","JPN":"空にいる艦船の数がわかりますか？　シャレードにいるすべてのタスクフォースカンパニーが出動したようです！","ENG":"See those ships in the sky? It seems like every TASKFORCE in Charade is on the move!","TWN":"有看到在天上的艦船嗎？查雷德的特遣勢力似乎全員出動中喔！"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L7_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"다들 그 얘기 들었지? 그 사채업자만 잡으면 관리국이 현상금을 두둑하게 준다던데?","JPN":"みんな、あの話を聞いたわよね？　あの闇金業者を捕まえたら管理局から懸賞金をたっぷりもらえるって！","ENG":"You guys heard the news, right? The Administration is offering one heck of a bounty for whoever catches that loan shark!","TWN":"大家應該都有聽說吧？只要逮到那個放高利貸的，管理局好像就大大有賞喔？"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"이거 혹시 나를 위해 마련된 찬스?","JPN":"これはもしかして、アタシのために用意されたチャンスかしら？","ENG":"Could this be the chance of my life?","TWN":"難道這是上天給我的大好機會？"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"여기서 활약하면 단숨에 유명인이 될 수 있다구!","JPN":"ここで活躍すれば一気に有名人になれるっ！","ENG":"If I kick some serious butt with this, I might become a superstar!","TWN":"只要這時候表現突出，應該就可以立刻爆紅吧！"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"아, 안 돼! 루미야! 저런 난장판에 끼어들면 큰일나!","JPN":"だ、だめだよ、ルミちゃん！　あんな乱闘の場に乗り込んだら大変なことになるよ！","ENG":"No! Lumi! You don't want to get mixed up in that mess, trust me!","TWN":"不…不可以啦，魯米！不要去淌那個渾水！"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"관리국 직할 도시이기 때문인지 방해가 계속되는군요.","JPN":"管理局直轄都市だからか、妨害が絶えませんね。","ENG":"So the interference continues, perhaps due to this city's ADC status.","TWN":"因為是管理局的直轄市嗎？一直會有阻礙出現。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"하지만 윌버, 이걸 믿고 지불을 거절한다면 신속히 생각을 바꿔야 할 겁니다.","JPN":"しかしウィルバー、この状況に頼って返済を拒絶し続けるなら、今のうちに考え直したほうがいいでしょう。","ENG":"But mark my words, Wilbur. You may want to rethink your strategy if you believe this will prevent me from collecting what is owed to me.","TWN":"不過韋爾伯，如果你以為這樣就可以不還錢，那你很快就會改變想法的。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"사격 감지. 탄착군 패턴 분석 결과 입체기동 중인 아라크네로 판명.","JPN":"射撃感知。射弾パターン分析の結果、立体起動中のアラクネと判明。","ENG":"Gunfire detected. Ballistic analysis suggests the source of fire is an Arachne in motion.","TWN":"感應到射擊，模式分析結果，判斷是立體機動中的阿拉克涅。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ARACHNE_FAW_NULL_NULL","text":{"KOREA":"도시관리국에서 파견되었습니다. 수배자는 즉시 무장을 해제하고 투항하십시오.","JPN":"都市管理局から派遣されました。指名手配被疑者は直ちに武装を解除して投降してください。","ENG":"This law enforcement activity is sanctioned by City Management. Put down your weapon and surrender immediately.","TWN":"受城市管理局之託而來，請通緝犯立刻放下武器投降。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARACHNE_FAW_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_TANK_SMALL_START"},{"id":"L22_1","type":"dialog","speaker":"ARACHNE_FAW_NULL_NULL","text":{"KOREA":"본 기체들은 퓨처 앳 워 재단에서 공여되었습니다.","JPN":"本機体はフューチャーアットウォー財団から供与されました。","ENG":"These machines have been supplied by the Future-at-War Foundation.","TWN":"本機體是由天啟兵器財團贈與。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ARACHNE_FAW_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_MECHANIC_TANK_SMALL_START"},{"id":"L24_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"……퓨처 앳 워 프로젝트가 남긴 찌꺼기로 연명하는 자들이 보낸 기체들이군요.","JPN":"……フューチャーアットウォープロジェクトの残滓で延命している者たちが送った機体ですね。","ENG":"…So you've been deployed by those who prolonged their lives with the leftovers from Future-at-War projects.","TWN":"……原來是天啟兵器計畫遺留下來的禍害派來的。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"하지만 아무리 펌웨어 업데이트를 해도 대인 기총으로 저를 저지할 수 있는 가능성은 0입니다.","JPN":"しかし、いくらファームウェアアップデートをしたところで対人機銃で私を阻止できる可能性は0です。","ENG":"But your anti-personnel rifles have exactly zero chance of neutralizing me, regardless of your firmware version.","TWN":"不過就算再怎麼更新韌體，可以用槍打死我的機率是0。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"TITAN_FAW_NULL_SMALL","text":{"KOREA":"수배자에게 경고한다. 투항하지 않겠다면 화력으로 제압하겠다.","JPN":"指名手配被疑者に警告。投降しなければ火力で制圧する。","ENG":"This is a warning. We will use lethal force if you do not surrender.","TWN":"警告通緝犯，若再不投降，將進行武力制裁。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_SMALL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_21"},{"id":"L35_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"저건…… 타이탄?","JPN":"あれは……タイタン？","ENG":"Is that… a Titan?","TWN":"那是……泰坦？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"TITAN_FAW_NULL_SMALL","text":{"KOREA":"네. 저는 제 3종 침식체 대항 병기 타이탄의 양산형 기체입니다.","JPN":"はい、私は第3種侵食体対抗兵器タイタンの量産型機体です。","ENG":"Affirmative. I am one of the many Titan units mass produced in order to deter Category 3 C.O.s.","TWN":"是，我是專門對抗3類侵蝕體的量產型泰坦。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_SMALL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"TITAN_FAW_NULL_SMALL","text":{"KOREA":"본 기체는 퓨처 앳 워 재단에서 공여되었습니다. 우리 재단은 인류의 미래를 수호합니다.","JPN":"本機体はフューチャーアットウォー財団から供与されました。当財団は人類の未来を守護します。","ENG":"This machine has been supplied by Future-at-War Foundation. The Foundation strives to safeguard the future of humanity.","TWN":"本機體是由天啟兵器財團贈與。人類的未來，我們的財團來守護。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_SMALL","face":"UNIT_TOUCH"},"R":null}},"sfx":"FX_COMBAT_ALL_TECH"},{"id":"L40_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"……강인공지능이 탑재되지 않은 모델이었습니까.","JPN":"……強人工知能が搭載されていないモデルでしたか。","ENG":"…So this model hasn't been installed with a strong A.I.","TWN":"……是沒有搭載高度人工智慧的機型嗎？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"제 의사소통 모듈에 기념비적인 비난 로그를 남길 시기가 다시 한 번 유예되었군요.","JPN":"私の意思疎通モジュールに記念碑的な非難ログを残す時期が猶予されましたね。","ENG":"Once again, the timing for leaving a monumental log of profanity in my communication module has been deferred.","TWN":"那看來暫時還不會有人檢討我的溝通模組。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"TITAN_FAW_NULL_SMALL","text":{"KOREA":"그렇습니다. 저는 양산을 위해 설계된 인공지능으로서, 성능적 한계에도 인류의 평화를 위해 힘껏 싸우고 있습니다.","JPN":"そうです。私は量産のために設計された人工知能として、性能的限界にも関わらず人類の平和のために精一杯戦っています。","ENG":"Affirmative. I am an A.I. designed for mass production. Despite my technical limitations, I strive my utmost to safeguard peace for all humankind.","TWN":"沒錯，我是設計來量產的人工智慧，雖然性能有限，但我將盡全力為人類的和平而戰。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_SMALL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"하지만 확실히, 비용과 성능 간의 타협을 통해 대량생산 공정의 간택을 받은 성공적인 양산기라니…….","JPN":"しかし確かに、コストと性能間の妥協によって大量生産に選ばれ、成功した量産機とは……","ENG":"Even so, you've been forged in the crucible of compromise between economy and performance for the sake of mass production…","TWN":"不過可以確定的是，妥協於經費和性能，選擇大量生產的機型，不能算是成功量產……"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"이건 이것대로 CPU 온도를 상승하게 만드는 요인이군요.","JPN":"これはこれで、CPU温度が上昇する要因になりますね。","ENG":"This too is reason enough to unduly increase the temperature of my CPU.","TWN":"這就是導致CPU溫度上升的原因吧？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"그 프레임에 탑재된 상태로 잘난 듯이 제 렌즈 앞에 나타난 폭거는 용납 못 하겠습니다.","JPN":"そのフレームに搭載された状態で、偉そうに私のレンズの前に現れた暴挙は許せません。","ENG":"I will not tolerate such hubris... appearing before my optic sensors in that frame.","TWN":"搭載在那樣的軀殼上，還一副很厲害的樣子出現在我面前，無法原諒。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"당장…… 거기서 분리시켜 드리겠습니다.","JPN":"直ちに……そこから分離させていただきます。","ENG":"I will… separate you from there at once.","TWN":"立刻……替你進行解體。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};